const pptxgen = require("pptxgenjs");
const { html2pptx } = require("./html2pptx");
const path = require("path");

async function createPresentation() {
  const pptx = new pptxgen();
  pptx.layout = "LAYOUT_16x9";
  pptx.title = "Jacksonville UI/UX Design Community - Strategic Playbook";
  pptx.author = "Jacksonville Design Leadership";
  pptx.subject = "Knowledge Repository Development & Community Excellence";

  const slides = [
    "slide01.html", // Title
    "slide02.html", // Contents
    "slide03.html", // Jacksonville Paradox
    "slide04.html", // Founding Principle
    "slide05.html", // Strategic Objectives
    "slide06.html", // Part One Section
    "slide07.html", // Knowledge Types
    "slide08.html", // Knowledge Lifecycle
    "slide09.html", // Slack Architecture
    "slide10.html", // Notion Architecture
    "slide11.html", // Part Two Section
    "slide12.html", // Employer Landscape
    "slide13.html", // Partnership Tiers
    "slide14.html", // Part Three Section
    "slide15.html", // Event Formats
    "slide16.html", // Part Four Section
    "slide17.html", // Leadership Structure
    "slide18.html", // Part Five Section
    "slide19.html", // Implementation Timeline
    "slide20.html", // Closing
  ];

  for (const slideFile of slides) {
    const slidePath = path.join(__dirname, "presentation", slideFile);
    await html2pptx(slidePath, pptx);
    console.log(`Processed: ${slideFile}`);
  }

  const outputPath = "/mnt/user-data/outputs/Jacksonville-Design-Community-Visual-Playbook.pptx";
  await pptx.writeFile(outputPath);
  console.log(`\nPresentation saved to: ${outputPath}`);
}

createPresentation().catch(console.error);

